from typing import List

class Solution:
    def areaOfMaxDiagonal(self, dimensions: List[List[int]]) -> int:
        max_diag = 0
        max_area = 0
        for length, width in dimensions:
            diag = length * length + width * width
            if diag > max_diag:
                max_diag = diag
                max_area = length * width
            elif diag == max_diag:
                if length * width > max_area:
                    max_area = length * width
        return max_area
